import "@/App.css";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
  Outlet,
} from "react-router-dom";

import axios from "axios";
import { Toaster } from "@/components/ui/sonner";
import { useEffect, useState } from "react";

// ======================
// PAGES
// ======================
import LandingPage from "@/pages/LandingPage";
import SchoolProfilePage from "@/pages/SchoolProfilePage";

import LoginPage from "@/pages/LoginPage";
import RegisterPage from "@/pages/RegisterPage";
import JoinSchoolPage from "@/pages/JoinSchoolPage";

// ======================
// LAYOUT
// ======================
import DashboardLayout from "@/components/layouts/DashboardLayout";

// ======================
// CORE
// ======================
import Dashboard from "@/pages/Dashboard";
import StudentsPage from "@/pages/StudentsPage";
import StaffPage from "@/pages/StaffPage";
import FeesPage from "@/pages/FeesPage";
import AttendancePage from "@/pages/AttendancePage";
import ExamsPage from "@/pages/ExamsPage";
import TimetablePage from "@/pages/TimetablePage";
import InventoryPage from "@/pages/InventoryPage";

// ======================
// PORTALS
// ======================
import StudentPortal from "@/pages/StudentPortal";
import TeacherPortal from "@/pages/TeacherPortal";
import FinancePortal from "@/pages/FinancePortal";
import SecretaryPortal from "@/pages/SecretaryPortal";

// ======================
// ADMIN
// ======================
import SuperAdminDashboard from "@/pages/SuperAdminDashboard";
import AnnouncementsPage from "@/pages/AnnouncementsPage";

// ======================
// DEBUG
// ======================
import DataExplorer from "@/pages/DataExplorer";

// ======================
// BACKEND
// ======================
const BACKEND_URL =
  process.env.REACT_APP_BACKEND_URL || "http://localhost:8000";

export const API = `${BACKEND_URL.replace(/\/$/, "")}/api`;

// ======================
// ROLE NORMALIZER
// ======================
export const normalizeRole = (role) => {
  if (!role) return "";

  const r = String(role).trim().toLowerCase();

  const roleMap = {
    admin: "SCHOOL_ADMIN",
    schooladmin: "SCHOOL_ADMIN",
    school_admin: "SCHOOL_ADMIN",

    superadmin: "SUPER_ADMIN",
    super_admin: "SUPER_ADMIN",

    teacher: "TEACHER",
    finance: "FINANCE",
    secretary: "SECRETARY",

    student: "STUDENT",
    parent: "STUDENT",
  };

  return roleMap[r] || r.toUpperCase();
};

// ======================
// AUTH SERVICE
// ======================
export const authService = {
  getToken: () => localStorage.getItem("token"),

  getUser: () => {
    try {
      const user = localStorage.getItem("user");
      if (!user || user === "undefined") return null;

      return {
        ...JSON.parse(user),
        role: normalizeRole(JSON.parse(user)?.role),
      };
    } catch {
      return null;
    }
  },

  setAuth: (token, user) => {
    if (!token || !user) return;

    localStorage.setItem("token", String(token));
    localStorage.setItem(
      "user",
      JSON.stringify({
        ...user,
        role: normalizeRole(user?.role),
      })
    );

    window.dispatchEvent(new Event("auth-change"));
  },

  clearAuth: () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    window.dispatchEvent(new Event("auth-change"));
  },

  isAuthenticated: () => !!localStorage.getItem("token"),

  getRole: () => authService.getUser()?.role || null,
};

// ======================
// AXIOS
// ======================
export const apiClient = axios.create({
  baseURL: API,
  timeout: 30000,
});

apiClient.interceptors.request.use((config) => {
  const token = authService.getToken();

  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  config.headers["Content-Type"] = "application/json";
  return config;
});

apiClient.interceptors.response.use(
  (res) => res,
  (error) => {
    const status = error?.response?.status;

    if (status === 401) {
      authService.clearAuth();
      window.dispatchEvent(new Event("force-logout"));
    }

    return Promise.reject(error);
  }
);

// ======================
// ROLE ROUTES
// ======================
const getDefaultRouteByRole = (role) => {
  switch (normalizeRole(role)) {
    case "SUPER_ADMIN":
      return "/app/super-admin";
    case "SCHOOL_ADMIN":
      return "/app/dashboard";
    case "TEACHER":
      return "/app/teacher-portal";
    case "FINANCE":
      return "/app/finance-portal";
    case "SECRETARY":
      return "/app/secretary-portal";
    case "STUDENT":
      return "/app/student-portal";
    default:
      return "/login";
  }
};

// ======================
// PERMISSIONS
// ======================
const routePermissions = {
  dashboard: ["SUPER_ADMIN", "SCHOOL_ADMIN", "TEACHER", "FINANCE", "SECRETARY"],
  students: ["SCHOOL_ADMIN", "SECRETARY", "TEACHER"],
  staff: ["SUPER_ADMIN", "SCHOOL_ADMIN"],
  fees: ["SCHOOL_ADMIN", "FINANCE"],
  attendance: ["SCHOOL_ADMIN", "TEACHER", "SECRETARY"],
  exams: ["SCHOOL_ADMIN", "TEACHER"],
  timetable: ["SCHOOL_ADMIN", "TEACHER", "STUDENT"],
  inventory: ["SCHOOL_ADMIN", "SECRETARY"],
  announcements: ["SCHOOL_ADMIN", "SECRETARY", "TEACHER", "FINANCE", "STUDENT"],
  "teacher-portal": ["TEACHER", "SCHOOL_ADMIN"],
  "finance-portal": ["FINANCE", "SCHOOL_ADMIN"],
  "secretary-portal": ["SECRETARY", "SCHOOL_ADMIN"],
  "student-portal": ["STUDENT"],
  "super-admin": ["SUPER_ADMIN"],
  debug: ["SUPER_ADMIN", "SCHOOL_ADMIN"],
};

// ======================
// GUARDS
// ======================
const ProtectedRoute = () => {
  if (!authService.getToken()) {
    return <Navigate to="/login" replace />;
  }
  return <Outlet />;
};

const RoleProtectedRoute = ({ routeKey, children }) => {
  const user = authService.getUser();

  if (!user) return <Navigate to="/login" replace />;

  const role = normalizeRole(user.role);
  const allowed = routePermissions[routeKey] || [];

  if (!allowed.includes(role)) {
    return (
      <Navigate
        to={getDefaultRouteByRole(role)}
        replace
      />
    );
  }

  return children;
};

// ======================
// LAYOUT WRAPPER
// ======================
const SafeDashboardLayout = () => {
  const location = useLocation();
  const user = authService.getUser();
  const token = authService.getToken();

  useEffect(() => {
    if (!user || !token) {
      authService.clearAuth();
    }
  }, [user, token]);

  if (!user || !token) {
    return <Navigate to="/login" replace />;
  }

  return (
    <DashboardLayout
      key={`${location.pathname}-${user.role}`}
    />
  );
};

// ======================
// ROOT REDIRECT
// ======================
const AppRootRedirect = () => {
  const role = authService.getRole();

  if (!role) return <Navigate to="/login" replace />;

  return (
    <Navigate
      to={getDefaultRouteByRole(role)}
      replace
    />
  );
};

// ======================
// APP
// ======================
function App() {
  return (
    <div className="App">
      <BrowserRouter>
        <Routes>

          {/* PUBLIC */}
          <Route path="/" element={<LandingPage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/register-school" element={<RegisterPage />} />
          <Route path="/setup-school" element={<SchoolProfilePage />} />
          <Route path="/join-school" element={<JoinSchoolPage />} />
          <Route path="/join/:inviteCode" element={<JoinSchoolPage />} />

          {/* PROTECTED */}
          <Route element={<ProtectedRoute />}>
            <Route path="/app" element={<SafeDashboardLayout />}>
              <Route index element={<AppRootRedirect />} />

              <Route
                path="dashboard"
                element={<RoleProtectedRoute routeKey="dashboard"><Dashboard /></RoleProtectedRoute>}
              />

              <Route
                path="students"
                element={<RoleProtectedRoute routeKey="students"><StudentsPage /></RoleProtectedRoute>}
              />

              <Route
                path="staff"
                element={<RoleProtectedRoute routeKey="staff"><StaffPage /></RoleProtectedRoute>}
              />

              <Route
                path="fees"
                element={<RoleProtectedRoute routeKey="fees"><FeesPage /></RoleProtectedRoute>}
              />

              <Route
                path="attendance"
                element={<RoleProtectedRoute routeKey="attendance"><AttendancePage /></RoleProtectedRoute>}
              />

              <Route
                path="exams"
                element={<RoleProtectedRoute routeKey="exams"><ExamsPage /></RoleProtectedRoute>}
              />

              <Route
                path="timetable"
                element={<RoleProtectedRoute routeKey="timetable"><TimetablePage /></RoleProtectedRoute>}
              />

              <Route
                path="inventory"
                element={<RoleProtectedRoute routeKey="inventory"><InventoryPage /></RoleProtectedRoute>}
              />

              <Route
                path="announcements"
                element={<RoleProtectedRoute routeKey="announcements"><AnnouncementsPage /></RoleProtectedRoute>}
              />

              <Route
                path="student-portal"
                element={<RoleProtectedRoute routeKey="student-portal"><StudentPortal /></RoleProtectedRoute>}
              />

              <Route
                path="teacher-portal"
                element={<RoleProtectedRoute routeKey="teacher-portal"><TeacherPortal /></RoleProtectedRoute>}
              />

              <Route
                path="finance-portal"
                element={<RoleProtectedRoute routeKey="finance-portal"><FinancePortal /></RoleProtectedRoute>}
              />

              <Route
                path="secretary-portal"
                element={<RoleProtectedRoute routeKey="secretary-portal"><SecretaryPortal /></RoleProtectedRoute>}
              />

              <Route
                path="super-admin"
                element={<RoleProtectedRoute routeKey="super-admin"><SuperAdminDashboard /></RoleProtectedRoute>}
              />

              <Route
                path="debug"
                element={<RoleProtectedRoute routeKey="debug"><DataExplorer /></RoleProtectedRoute>}
              />

            </Route>
          </Route>

          {/* FALLBACK */}
          <Route path="*" element={<Navigate to="/" replace />} />

        </Routes>
      </BrowserRouter>

      <Toaster position="top-right" richColors />
    </div>
  );
}

export default App;
